self.onmessage=async s=>{const{id:t,...e}=s.data;for(const s of Object.keys(e))self[s]=e[s];try{let s;if(t<0){const t=self.pyodide;importScripts(t);const e=t.replace(/\/[^/]*$/,"/");self.pyodide=await loadPyodide({indexURL:e}),s=await self.pyodide.runPythonAsync("\n      import micropip\n      from js import packages, optlite\n      await micropip.install(optlite)\n      for p in packages:\n          await micropip.install(p)\n      ")}else await self.pyodide.loadPackagesFromImports(self.script),s=await self.pyodide.runPythonAsync("\n      import optlite\n      from js import script, rawInputLst\n      optlite.exec_script(script, rawInputLst)\n      ");self.postMessage({results:s,id:t})}catch(s){self.postMessage({error:"Failed to run code: "+s.message,id:t})}};